mapper.update:
UPDATE notifications
SET read_at = #{readAt}
WHERE notification_id = #{notificationId} AND `user` = #{user} AND read_at IS NULL

mapper.select:
SELECT id, notification_id AS notificationId, user_id AS userId,
       channel, payload, retry_count AS retryCount
FROM notification_outbox
WHERE status = 'PENDING' AND retry_after <= #{now}
ORDER BY id
LIMIT #{limit}

mapper.update:
UPDATE notification_outbox
SET status = 'PENDING', locked_by = NULL, locked_at = NULL
WHERE status = 'PROCESSING' AND locked_at < #{cutoff}

UPDATE notification_outbox
SET status = 'PROCESSING', locked_by = #{workerId}, locked_at = #{lockedAt}
WHERE id = #{id} AND status = 'PENDING'

UPDATE notification_outbox
SET status = 'SENT', sent_at = #{sentAt}, locked_by = NULL, locked_at = NULL
WHERE id = #{id}

UPDATE notification_outbox
SET status = 'DLQ', last_error = #{lastError}, locked_by = NULL, locked_at = NULL
WHERE id = #{id}
